#include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;cmath&gt;using namespace std;void f1(vector&lt;int&gt; v);void f2(vector&lt;int&gt; v);void f3(vector&lt;int&gt; v);void f4(vector&lt;int&gt; v);void f5(vector&lt;int&gt; v);int main() &#123;    int n;    vector&lt;int&gt; v;    while(cin &gt;&gt; n)        v.push_back(n);        f1(v);    f2(v);    f3(v);    f4(v);    f5(v);        return 0;&#125;void f1(vector&lt;int&gt; v)&#123;    int sum = 0,count=0;    for (int i=1;i&lt;v.size();i++)&#123;        if((v[i]%5==0)&amp;&amp;(v[i]%2==0))&#123;            sum += v[i];            count++;        &#125;    &#125;    if (count!=0)        cout &lt;&lt; sum &lt;&lt; &quot; &quot;;    else if(count==0)        cout &lt;&lt; &quot;N &quot;;&#125;void f2(vector&lt;int&gt; v)&#123;    int sum=0,count=0;    for (int i=1;i&lt;v.size();i++)&#123;        if (v[i]%5==1)&#123;            sum += v[i]*(int)pow(-1.0,(double)count);            count++;        &#125;    &#125;    if (count!=0)        cout &lt;&lt; sum &lt;&lt; &quot; &quot;;    else         cout &lt;&lt; &quot;N &quot;;&#125;void f3(vector&lt;int&gt; v)&#123;    int count=0;    for (int i=1;i&lt;v.size();i++)&#123;        if(v[i]%5==2) count++;    &#125;    if (count!=0)        cout &lt;&lt; count &lt;&lt; &quot; &quot;;    else         cout &lt;&lt; &quot;N &quot;;&#125;void f4(vector&lt;int&gt; v)&#123;    float average=0,count=0;    for (int i=1;i&lt;v.size();i++)&#123;        if(v[i]%5==3)&#123;            average += (float)v[i];            count++;        &#125;    &#125;    average /= count;    if (count!=0)        printf(&quot;%0.1f &quot;,average);    else         cout &lt;&lt; &quot;N &quot;;&#125;void f5(vector&lt;int&gt; v)&#123;    int max=0,count=0;    for (int i=1;i&lt;v.size();i++)        if (v[i]%5==4)            if(v[i]&gt;max)&#123;                max = v[i];                count++;            &#125;    if (count!=0)        cout &lt;&lt; max;    else         cout &lt;&lt; &quot;N&quot;;&#125;

