1014 福尔摩斯的约会 (20 分)#include &lt;iostream&gt;#include &lt;cctype&gt;#include &lt;string&gt;using namespace std;int main()&#123;    string a,b,c,d;    cin &gt;&gt; a &gt;&gt; b &gt;&gt; c &gt;&gt; d;        // 先处理前两句    char ch[2];    int i=0;    for(i; i&lt;a.length() &amp;&amp; i&lt;b.length(); i++)&#123;        if(a[i] == b[i] &amp;&amp; (a[i] &gt;= &#x27;A&#x27; &amp;&amp; a[i] &lt;= &#x27;G&#x27;))&#123;            ch[0] = a[i];            break;        &#125;    &#125;    i = i+1;    for(i; i&lt;a.length() &amp;&amp; i&lt;b.length(); i++)&#123;        if (a[i]==b[i] &amp;&amp; ((a[i] &gt;= &#x27;A&#x27; &amp;&amp; a[i] &lt;= &#x27;N&#x27;) ||isdigit(a[i])))&#123;            ch[1] = a[i];            break;        &#125;         &#125;        // 再处理后两句    int j = 0, pos;    for (j;j&lt;c.length() &amp;&amp; j&lt;d.length();j++)&#123;        if(c[j] == d[j] &amp;&amp; isalpha(c[j]))&#123;            pos = j;            break;        &#125;    &#125;        // 输出    string week[7] = &#123;&quot;MON &quot;, &quot;TUE &quot;, &quot;WED &quot;, &quot;THU &quot;, &quot;FRI &quot;, &quot;SAT &quot;, &quot;SUN &quot;&#125;;    cout &lt;&lt; week[ch[0]-&#x27;A&#x27;];    int m = isdigit(ch[1]) ? ch[1] - &#x27;0&#x27; : ch[1] - &#x27;A&#x27; + 10;    printf(&quot;%02d:%02d&quot;, m, pos);    return 0;&#125;

1015 德才论 (25 分)#include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;algorithm&gt;using namespace std;struct node &#123;    int num, de, cai;&#125;;int cmp(struct node a ,struct node b)&#123;    if ((a.de + a.cai) != (b.de + b.cai))        return (a.de + a.cai) &gt; (b.de + b.cai);    else if (a.de != b.de)        return a.de &gt; b.de;    else        return a.num &lt; b.num;&#125;int main()&#123;    int n, low, high;    cin &gt;&gt; n &gt;&gt; low &gt;&gt; high;    vector&lt;node&gt; v[4];    node temp;    int total = n;    for(int i=0; i&lt;n; i++)&#123;        cin &gt;&gt; temp.num &gt;&gt; temp.de &gt;&gt; temp.cai;        if(temp.de &lt; low || temp.cai &lt; low)            total --;        else if(temp.de &gt;= high &amp;&amp; temp.cai &gt;= high)            v[0].push_back(temp);        else if(temp.de &gt;= high &amp;&amp; temp.cai &lt; high)            v[1].push_back(temp);        else if(temp.de &lt; high &amp;&amp; temp.cai &lt; high &amp;&amp; temp.de &gt;= temp.cai)            v[2].push_back(temp);        else            v[3].push_back(temp);    &#125;    cout &lt;&lt; total &lt;&lt; endl;    for (int i=0; i&lt;4;i++)&#123;        sort(v[i].begin(), v[i].end(), cmp);        for (int j=0; j&lt;v[i].size(); j++)            cout &lt;&lt; v[i][j].num &lt;&lt; &quot; &quot; &lt;&lt; v[i][j].de &lt;&lt; &quot; &quot; &lt;&lt; v[i][j].cai &lt;&lt; endl;    &#125;    return 0;&#125;

