void quick_sort(int q[], int l, int r)&#123;    if(l&gt;=r) return; //区间内只有1个或者没有元素直接返回        //i为左指针，j为右指针，注意边界    int i = l-1, j = r+1, x = q[l+r&gt;&gt;1]; //l+r的值右移1位，相当l+r的值除以2取整。    while(i&lt;j)&#123; //左指针小于右指针        do i++; while(q[i] &lt; x); //指针i右移，x左边的数小于x就循环        do j--; while(q[j] &gt; x); //指针j左移，x右边的数大于x就循环        if(i &lt; j) swap(q[i], q[j]); //如果左右指针没有相遇，就交换所指元素的位置    &#125;    //递归处理左右两段    quick_sort(q, l, j)，quick_sort(q, j+1, r);&#125;

