void merge_sort(int p[], l, r)&#123;    if(l&gt;=r) return; //区间内只有1个或者没有元素直接返回        int mid = l+r&gt;&gt;1;    merge_sort(p, l, mid);    merge_sort(p, mid+1, r);        int tmp[N]; //开辟一个临时数组保存结果，N可以依据题目定义在函数体外    int k = 0, i = 1, j = mid + 1; //k表示当前tmp里面已经存了多少个数    while(i &lt;= mid &amp;&amp; j &lt;= r)&#123;        if (q[i] &lt;= q[j]) tmp[k++] = q[i++]; //把小的存入tmp中（从小到大排）        else tmp[k++] = q[j++];    &#125;    while(i &lt;= mid) tmp[k++] = q[i++]; //左半边有剩余就把剩余的连上去    while(j &lt;= r) tmp[k++] = q[j++];//右半边有剩余就把剩余的连上去        for(i = l, j=0;i &lt;= r; i++, j++) q[i] = tmp[j]; //最后将tmp复制回q&#125;

